// Solution
function validateRouteParameters(req, res, next) {
  const routeParams = req.params;
  const jsonBody = req.body;
  if (Object.keys(jsonBody).length !== Object.keys(routeParams).length) {
    next(new Error('Invalid route parameters'));
    return;
  }
  for (const key in jsonBody) {
    if (jsonBody[key] !== routeParams[key]) {
      next(new Error('Invalid route parameters'));
      return;
    }
  }
  next();
}
